const PptxGenJS = require('pptxgenjs');
const path = require('node:path');

const GRADIENT_PNG = 'data:image/png;base64,';

const pptx = new PptxGenJS();
pptx.defineLayout({ name: 'KPMG_WIDE', width: 13.333, height: 7.5 });
pptx.layout = 'KPMG_WIDE';

const slide = pptx.addSlide();

// Divider window placement matching slideLayout10.xml (Divider slide_5)
slide.addImage({
  data: GRADIENT_PNG,
  x: 1.0919466,
  y: 1.0674245,
  w: 7.7228631,
  h: 5.3645833
});

// Add text on top (layering test)
slide.addText('01', {
  x: 1.25,
  y: 1.20,
  w: 2.0,
  h: 1.0,
  fontFace: 'Arial',
  fontSize: 72,
  color: 'FFFFFF',
  bold: true
});

pptx.writeFile({ fileName: path.join(__dirname, '..', '..', 'references', 'pptx', 'gradient-test.pptx') });
